mapper.select:
/* PrepaidCardStatusMapper.getPrepaidCardChargeStatus */



    SELECT  tms.BRANCH_CD
    ,       (SELECT BRANCH_NM FROM TB_HQ_BRANCH_MOMS thbm WHERE thbm.HQ_OFFICE_CD = tms.HQ_OFFICE_CD AND thbm.BRANCH_CD = tms.BRANCH_CD) AS BRANCH_NM
    ,       tnnh.STORE_CD
    ,       tms.STORE_NM
    ,       tms.HQ_BRAND_CD AS BRAND_CD
    ,       tmsi.MOMS_TEAM
    ,       tmsi.MOMS_AC_SHOP
    ,       SUM(CASE WHEN tnnh.SALE_YN = 'Y' THEN 1 ELSE 0 END) AS CHARGE_CNT
    ,       SUM(CASE WHEN tnnh.SALE_YN = 'Y' THEN tnnh.AMOUNT ELSE 0 END) AS TOT_CHARGE_AMT
    ,       SUM(CASE WHEN tnnh.SALE_YN = 'N' THEN 1 ELSE 0 END) AS CHARGE_CANCEL_CNT
    ,       SUM(CASE WHEN tnnh.SALE_YN = 'N' THEN tnnh.AMOUNT ELSE 0 END) AS TOT_CHARGE_CANCEL_AMT

    FROM    TB_NS_NONSALE_PREPAID_CHARGE tnnh
    ,       TB_MS_STORE tms
    ,       TB_MS_STORE_INFO tmsi
    WHERE   tnnh.HQ_OFFICE_CD = #{hqOfficeCd}
    AND     tnnh.SALE_DATE BETWEEN #{startDate} AND #{endDate}

        AND tnnh.SALE_YN = #{saleYn}


        AND tnnh.STORE_CD IN (${storeCdQuery})


        AND tms.HQ_BRAND_CD = #{storeHqBrandCd} -- 매장브랜드 선택일때



            -- 매장브랜드 전체일때
            AND tms.HQ_BRAND_CD IN

                #{item}




        AND tmsi.MOMS_TEAM = #{momsTeam}


        AND tmsi.MOMS_AC_SHOP = #{momsAcShop}


        AND tmsi.MOMS_AREA_FG = #{momsAreaFg}


        AND tmsi.MOMS_COMMERCIAL = #{momsCommercial}


        AND tmsi.MOMS_SHOP_TYPE = #{momsShopType}


        AND tmsi.MOMS_STORE_MANAGE_TYPE = #{momsStoreManageType}


        AND tms.BRANCH_CD = #{branchCd}


        AND tmsi.MOMS_STORE_FG_01 = #{momsStoreFg01}


        AND tmsi.MOMS_STORE_FG_02 = #{momsStoreFg02}


        AND tmsi.MOMS_STORE_FG_03 = #{momsStoreFg03}


        AND tmsi.MOMS_STORE_FG_04 = #{momsStoreFg04}


        AND tmsi.MOMS_STORE_FG_05 = #{momsStoreFg05}

    AND     tnnh.HQ_OFFICE_CD = tms.HQ_OFFICE_CD
    AND     tnnh.STORE_CD = tms.STORE_CD
    AND     tnnh.STORE_CD = tmsi.STORE_CD(+)
    GROUP
    BY      tms.HQ_OFFICE_CD
    ,       tms.HQ_BRAND_CD
    ,       tms.BRANCH_CD
    ,       tnnh.STORE_CD
    ,       tms.STORE_NM
    ,       tmsi.MOMS_TEAM
    ,       tmsi.MOMS_AC_SHOP
    ORDER
    BY      tnnh.STORE_CD



    SELECT  tnnh.STORE_CD
    ,       TO_CHAR(TO_DATE(tnnh.SALE_DATE, 'yyyymmdd'), 'yyyy-mm-dd') AS SALE_DATE
    ,       SUM(CASE WHEN tnnh.SALE_YN = 'Y' THEN 1 ELSE 0 END) AS CHARGE_CNT
    ,       SUM(CASE WHEN tnnh.SALE_YN = 'Y' THEN tnnh.AMOUNT ELSE 0 END) AS TOT_CHARGE_AMT
    ,       SUM(CASE WHEN tnnh.SALE_YN = 'N' THEN 1 ELSE 0 END) AS CHARGE_CANCEL_CNT
    ,       SUM(CASE WHEN tnnh.SALE_YN = 'N' THEN tnnh.AMOUNT ELSE 0 END) AS TOT_CHARGE_CANCEL_AMT

    FROM    TB_NS_NONSALE_PREPAID_CHARGE tnnh
    WHERE   tnnh.HQ_OFFICE_CD = #{hqOfficeCd}
    AND     tnnh.SALE_DATE BETWEEN #{startDate} AND #{endDate}

        AND tnnh.SALE_YN = #{saleYn}


        AND tnnh.STORE_CD IN (${storeCdQuery})

    GROUP
    BY      tnnh.STORE_CD
    ,       tnnh.SALE_DATE
    ORDER
    BY      tnnh.STORE_CD
    ,       tnnh.SALE_DATE DESC

/* PrepaidCardStatusMapper.getPrepaidCardUseStatus */



    SELECT  tms.BRANCH_CD
    ,       (SELECT BRANCH_NM FROM TB_HQ_BRANCH_MOMS thbm WHERE thbm.HQ_OFFICE_CD = tms.HQ_OFFICE_CD AND thbm.BRANCH_CD = tms.BRANCH_CD) AS BRANCH_NM
    ,       tsspv.STORE_CD
    ,       tms.STORE_NM
    ,       tms.HQ_BRAND_CD AS BRAND_CD
    ,       tmsi.MOMS_TEAM
    ,       tmsi.MOMS_AC_SHOP
    ,       SUM(CASE WHEN tsspv.SALE_YN = 'Y' THEN 1 ELSE 0 END) AS USE_CNT
    ,       SUM(CASE WHEN tsspv.SALE_YN = 'Y' THEN tsspv.SALE_AMT ELSE 0 END) AS TOT_USE_AMT
    ,       SUM(CASE WHEN tsspv.SALE_YN = 'N' THEN 1 ELSE 0 END) AS USE_CANCEL_CNT
    ,       SUM(CASE WHEN tsspv.SALE_YN = 'N' THEN tsspv.SALE_AMT ELSE 0 END) AS TOT_USE_CANCEL_AMT

    FROM    TB_SL_SALE_PAY_VCHARGE tsspv
    ,       TB_MS_STORE tms
    ,       TB_MS_STORE_INFO tmsi
    WHERE   tsspv.HQ_OFFICE_CD = #{hqOfficeCd}
    AND     tsspv.SALE_DATE BETWEEN #{startDate} AND #{endDate}

        AND tsspv.SALE_YN = #{saleYn}


        AND tsspv.STORE_CD IN (${storeCdQuery})


        AND tms.HQ_BRAND_CD = #{storeHqBrandCd} -- 매장브랜드 선택일때



            -- 매장브랜드 전체일때
            AND tms.HQ_BRAND_CD IN

                #{item}




        AND tmsi.MOMS_TEAM = #{momsTeam}


        AND tmsi.MOMS_AC_SHOP = #{momsAcShop}


        AND tmsi.MOMS_AREA_FG = #{momsAreaFg}


        AND tmsi.MOMS_COMMERCIAL = #{momsCommercial}


        AND tmsi.MOMS_SHOP_TYPE = #{momsShopType}


        AND tmsi.MOMS_STORE_MANAGE_TYPE = #{momsStoreManageType}


        AND tms.BRANCH_CD = #{branchCd}


        AND tmsi.MOMS_STORE_FG_01 = #{momsStoreFg01}


        AND tmsi.MOMS_STORE_FG_02 = #{momsStoreFg02}


        AND tmsi.MOMS_STORE_FG_03 = #{momsStoreFg03}


        AND tmsi.MOMS_STORE_FG_04 = #{momsStoreFg04}


        AND tmsi.MOMS_STORE_FG_05 = #{momsStoreFg05}

    AND     tsspv.HQ_OFFICE_CD = tms.HQ_OFFICE_CD
    AND     tsspv.STORE_CD = tms.STORE_CD
    AND     tsspv.STORE_CD = tmsi.STORE_CD(+)
    GROUP
    BY      tms.HQ_OFFICE_CD
    ,       tms.HQ_BRAND_CD
    ,       tms.BRANCH_CD
    ,       tsspv.STORE_CD
    ,       tms.STORE_NM
    ,       tmsi.MOMS_TEAM
    ,       tmsi.MOMS_AC_SHOP
    ORDER
    BY      tsspv.STORE_CD



    SELECT  tsspv.STORE_CD
    ,       TO_CHAR(TO_DATE(tsspv.SALE_DATE, 'yyyymmdd'), 'yyyy-mm-dd') AS SALE_DATE
    ,       SUM(CASE WHEN tsspv.SALE_YN = 'Y' THEN 1 ELSE 0 END) AS USE_CNT
    ,       SUM(CASE WHEN tsspv.SALE_YN = 'Y' THEN tsspv.SALE_AMT ELSE 0 END) AS TOT_USE_AMT
    ,       SUM(CASE WHEN tsspv.SALE_YN = 'N' THEN 1 ELSE 0 END) AS USE_CANCEL_CNT
    ,       SUM(CASE WHEN tsspv.SALE_YN = 'N' THEN tsspv.SALE_AMT ELSE 0 END) AS TOT_USE_CANCEL_AMT

    FROM    TB_SL_SALE_PAY_VCHARGE tsspv
    WHERE   tsspv.HQ_OFFICE_CD = #{hqOfficeCd}
    AND     tsspv.SALE_DATE BETWEEN #{startDate} AND #{endDate}

        AND tsspv.SALE_YN = #{saleYn}


        AND tsspv.STORE_CD IN (${storeCdQuery})

    GROUP
    BY      tsspv.STORE_CD
    ,       tsspv.SALE_DATE
    ORDER
    BY      tsspv.STORE_CD
    ,       tsspv.SALE_DATE DESC

/* PrepaidCardStatusMapper.getPrepaidCardChargeStatusDtl */
SELECT tnnh.STORE_CD , tms.STORE_NM , TO_CHAR(TO_DATE(tnnh.SALE_DATE, 'yyyymmdd'), 'yyyy-mm-dd') AS SALE_DATE , tnnh.POS_NO , tnnh.CHARGE_CARD_NO , SUM(CASE WHEN tnnh.SALE_YN = 'Y' THEN 1 ELSE 0 END) AS CHARGE_CNT , SUM(CASE WHEN tnnh.SALE_YN = 'Y' THEN tnnh.AMOUNT ELSE 0 END) AS TOT_CHARGE_AMT , SUM(CASE WHEN tnnh.SALE_YN = 'N' THEN 1 ELSE 0 END) AS CHARGE_CANCEL_CNT , SUM(CASE WHEN tnnh.SALE_YN = 'N' THEN tnnh.AMOUNT ELSE 0 END) AS TOT_CHARGE_CANCEL_AMT , MAX(tnnh.BALANCE) KEEP(DENSE_RANK LAST ORDER BY tnnh.CHARGE_DT) AS BALANCE FROM TB_NS_NONSALE_PREPAID_CHARGE tnnh , TB_MS_STORE tms WHERE tnnh.HQ_OFFICE_CD = #{hqOfficeCd} AND tnnh.SALE_DATE BETWEEN #{startDate} AND #{endDate}
AND tnnh.SALE_YN = #{saleYn}
AND tnnh.STORE_CD = #{storeCd} AND tnnh.HQ_OFFICE_CD = tms.HQ_OFFICE_CD AND tnnh.STORE_CD = tms.STORE_CD GROUP BY tnnh.STORE_CD , tms.STORE_NM , tnnh.SALE_DATE , tnnh.POS_NO , tnnh.CHARGE_CARD_NO ORDER BY tnnh.SALE_DATE , tnnh.POS_NO , tnnh.CHARGE_CARD_NO
SELECT TO_CHAR(TO_DATE(tnnh.SALE_DATE, 'yyyymmdd'), 'yyyy-mm-dd') AS SALE_DATE , tnnh.CHARGE_CARD_NO , SUM(CASE WHEN tnnh.SALE_YN = 'Y' THEN 1 ELSE 0 END) AS CHARGE_CNT , SUM(CASE WHEN tnnh.SALE_YN = 'Y' THEN tnnh.AMOUNT ELSE 0 END) AS TOT_CHARGE_AMT , SUM(CASE WHEN tnnh.SALE_YN = 'N' THEN 1 ELSE 0 END) AS CHARGE_CANCEL_CNT , SUM(CASE WHEN tnnh.SALE_YN = 'N' THEN tnnh.AMOUNT ELSE 0 END) AS TOT_CHARGE_CANCEL_AMT , MAX(tnnh.BALANCE) KEEP(DENSE_RANK LAST ORDER BY tnnh.CHARGE_DT) AS BALANCE FROM TB_NS_NONSALE_PREPAID_CHARGE tnnh WHERE tnnh.HQ_OFFICE_CD = #{hqOfficeCd} AND tnnh.SALE_DATE = #{saleDate}
AND tnnh.SALE_YN = #{saleYn}
AND tnnh.STORE_CD = #{storeCd} GROUP BY tnnh.SALE_DATE , tnnh.CHARGE_CARD_NO ORDER BY tnnh.SALE_DATE , tnnh.CHARGE_CARD_NO

/* PrepaidCardStatusMapper.getPrepaidCardUseStatusDtl */
SELECT tsspv.STORE_CD , tms.STORE_NM , TO_CHAR(TO_DATE(tsspv.SALE_DATE, 'yyyymmdd'), 'yyyy-mm-dd') AS SALE_DATE , tsspv.POS_NO , tsspv.VCHARGE_CARD_NO , SUM(CASE WHEN tsspv.SALE_YN = 'Y' THEN 1 ELSE 0 END) AS USE_CNT , SUM(CASE WHEN tsspv.SALE_YN = 'Y' THEN tsspv.SALE_AMT ELSE 0 END) AS TOT_USE_AMT , SUM(CASE WHEN tsspv.SALE_YN = 'N' THEN 1 ELSE 0 END) AS USE_CANCEL_CNT , SUM(CASE WHEN tsspv.SALE_YN = 'N' THEN tsspv.SALE_AMT ELSE 0 END) AS TOT_USE_CANCEL_AMT , MAX(tsspv.VCHARGE_REMAIN_AMT) KEEP(DENSE_RANK LAST ORDER BY tsspv.REG_DT) AS VCHARGE_REMAIN_AMT FROM TB_SL_SALE_PAY_VCHARGE tsspv , TB_MS_STORE tms WHERE tsspv.HQ_OFFICE_CD = #{hqOfficeCd} AND tsspv.SALE_DATE BETWEEN #{startDate} AND #{endDate}
AND tsspv.SALE_YN = #{saleYn}
AND tsspv.STORE_CD = #{storeCd} AND tsspv.HQ_OFFICE_CD = tms.HQ_OFFICE_CD AND tsspv.STORE_CD = tms.STORE_CD GROUP BY tsspv.STORE_CD , tms.STORE_NM , tsspv.SALE_DATE , tsspv.POS_NO , tsspv.VCHARGE_CARD_NO ORDER BY tsspv.SALE_DATE , tsspv.VCHARGE_CARD_NO
SELECT TO_CHAR(TO_DATE(tsspv.SALE_DATE, 'yyyymmdd'), 'yyyy-mm-dd') AS SALE_DATE , tsspv.VCHARGE_CARD_NO , SUM(CASE WHEN tsspv.SALE_YN = 'Y' THEN 1 ELSE 0 END) AS USE_CNT , SUM(CASE WHEN tsspv.SALE_YN = 'Y' THEN tsspv.SALE_AMT ELSE 0 END) AS TOT_USE_AMT , SUM(CASE WHEN tsspv.SALE_YN = 'N' THEN 1 ELSE 0 END) AS USE_CANCEL_CNT , SUM(CASE WHEN tsspv.SALE_YN = 'N' THEN tsspv.SALE_AMT ELSE 0 END) AS TOT_USE_CANCEL_AMT , MAX(tsspv.VCHARGE_REMAIN_AMT) KEEP(DENSE_RANK LAST ORDER BY tsspv.REG_DT) AS VCHARGE_REMAIN_AMT FROM TB_SL_SALE_PAY_VCHARGE tsspv WHERE tsspv.HQ_OFFICE_CD = #{hqOfficeCd} AND tsspv.SALE_DATE = #{saleDate}
AND tsspv.SALE_YN = #{saleYn}
AND tsspv.STORE_CD = #{storeCd} GROUP BY tsspv.SALE_DATE , tsspv.VCHARGE_CARD_NO ORDER BY tsspv.SALE_DATE , tsspv.VCHARGE_CARD_NO
